exec("import json, os, re, urllib.parse, urllib.request, urllib.error\nSEARCH='https://api.x.com/2/tweets/search/recent'\nPOST='https://api.x.com/2/tweets'\nOPENAI='https://api.openai.com/v1/responses'\ndef env(k):\n    v=os.environ.get(k,'').strip()\n    if not v: raise RuntimeError('missing '+k)\n    return v\ndef req(url,headers=None,data=None,method=None):\n    body=None if data is None else json.dumps(data,ensure_ascii=False).encode('utf-8')\n    r=urllib.request.Request(url,data=body,method=method or ('POST' if body else 'GET'),headers=headers or {})\n    try:\n        with urllib.request.urlopen(r,timeout=45) as x:\n            s=x.read().decode('utf-8')\n            return json.loads(s) if s else {}\n    except urllib.error.HTTPError as e:\n        raise RuntimeError('HTTP %s %s'%(e.code,e.read().decode('utf-8','replace')[:800]))\ndef latest():\n    q='(from:BloombergJapan \"\\\\u4eca\\\\u671d\\\\u306e5\\\\u672c\") OR (from:BloombergJapan \"\\\\u4eca\\\\u671d\\\\u306e\\\\uff15\\\\u672c\") -is:retweet'\n    p=urllib.parse.urlencode({'query':q,'max_results':'10','tweet.fields':'created_at,entities'})\n    d=req(SEARCH+'?'+p,{'Authorization':'Bearer '+env('X_BEARER_TOKEN')})\n    ts=sorted(d.get('data') or [],key=lambda x:x.get('created_at',''),reverse=True)\n    if not ts: raise RuntimeError('BloombergJapan tweet not found')\n    t=ts[0]\n    us=t.get('entities',{}).get('urls') or []\n    if not us: raise RuntimeError('tweet url not found')\n    u=us[0].get('unwound_url') or us[0].get('expanded_url') or us[0].get('url')\n    return t.get('text',''),u.split('?')[0]\ndef fetch(u):\n    r=urllib.request.Request(u,headers={'User-Agent':'Mozilla/5.0','Accept-Language':'ja,en;q=0.8'})\n    with urllib.request.urlopen(r,timeout=45) as x: return x.read().decode('utf-8','replace')\ndef article(u):\n    for x in (u,'https://r.jina.ai/'+u):\n        try:\n            s=fetch(x); s=re.sub('<script.*?</script>|<style.*?</style>',' ',s,flags=re.S|re.I); s=re.sub('<[^>]+>',' ',s); s=re.sub(r'\\\\s+',' ',s).strip()\n            if len(s)>300: return s[:6000]\n        except Exception: pass\n    return ''\ndef ai(prompt):\n    d=req(OPENAI,{'Authorization':'Bearer '+env('OPENAI_API_KEY'),'Content-Type':'application/json'},{'model':os.environ.get('OPENAI_MODEL','gpt-4.1-mini'),'input':prompt,'max_output_tokens':500})\n    if d.get('output_text'): return d['output_text'].strip()\n    out=[]\n    for i in d.get('output',[]):\n        for c in i.get('content',[]): out.append(c.get('text',''))\n    return ''.join(out).strip()\ndef make(tweet,u,text):\n    prompt='''Write one Japanese X post within 280 chars. Start exactly with \u3010\u30b5\u30e9\u30ea\u30fc\u30de\u30f3\u5fc5\u898b\u3011. Summarize Bloomberg Japan \u4eca\u671d\u306e5\u672c in 5 short numbered items. Add market view lines like \u2191\u2191sector\u30fbcommodity and \u2193\u2193currency\u30fbsector. Put the article URL at the end. No quotes, no explanation.\\nTweet:\\n%s\\nURL:%s\\nArticle:\\n%s'''%(tweet,u,text)\n    p=ai(prompt).strip().strip('\"')\n    if not p.startswith('\u3010\u30b5\u30e9\u30ea\u30fc\u30de\u30f3\u5fc5\u898b\u3011'): p='\u3010\u30b5\u30e9\u30ea\u30fc\u30de\u30f3\u5fc5\u898b\u3011'+p\n    if u not in p: p=p.rstrip()+'\\n'+u\n    if len(p)>280:\n        keep='\\n'+u\n        p=p[:280-len(keep)-1].rstrip()+keep\n    return p\ndef post(x):\n    body=json.dumps({'text':x},ensure_ascii=False).encode('utf-8')\n    r=urllib.request.Request(POST,data=body,method='POST',headers={'Authorization':'Bearer '+env('X_USER_ACCESS_TOKEN'),'Content-Type':'application/json'})\n    with urllib.request.urlopen(r,timeout=45) as y: print(y.read().decode('utf-8'))\ndef main():\n    tw,u=latest(); p=make(tw,u,article(u) or tw); print(p)\n    if os.environ.get('DRY_RUN')!='1': post(p)\nmain()")
